// ============================================================
// src/pages/FinesPage.js
// Fine records displayed in table format with search/filter
// ============================================================
import React, { useState, useEffect, useMemo } from 'react';
import { finesAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';

const FinesPage = () => {
  const { currentUser } = useAuth();
  const isStudent = currentUser?.role === 'Student';

  // Filter state
  const [search,  setSearch]  = useState('');
  const [status,  setStatus]  = useState('All');
  const [sortCol, setSortCol] = useState('id');
  const [sortDir, setSortDir] = useState('asc');

  // Students only see their own fines
  const [fines, setFines] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchFines = isStudent ? finesAPI.getMyFines() : finesAPI.getAll();
    fetchFines
      .then(res => setFines(res.data || []))
      .catch(err => console.error("Error fetching fines:", err))
      .finally(() => setLoading(false));
  }, [isStudent]);

  const baseFines = fines;

  // ── Filter & sort ────────────────────────────────────────
  const filtered = useMemo(() => {
    let fines = baseFines;
    if (status !== 'All') fines = fines.filter(f => f.status === status);
    if (search.trim())
      fines = fines.filter(f =>
        (f.student?.name?.toLowerCase() || '').includes(search.toLowerCase()) ||
        (f.book?.title?.toLowerCase() || '').includes(search.toLowerCase())
      );
    return [...fines].sort((a, b) => {
      const av = a[sortCol], bv = b[sortCol];
      if (typeof av === 'string') return sortDir === 'asc' ? av.localeCompare(bv) : bv.localeCompare(av);
      return sortDir === 'asc' ? av - bv : bv - av;
    });
  }, [baseFines, search, status, sortCol, sortDir]);

  const toggleSort = (col) => {
    if (sortCol === col) setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    else { setSortCol(col); setSortDir('asc'); }
  };

  const SortIcon = ({ col }) => {
    if (sortCol !== col) return <i className="bi bi-chevron-expand ms-1 text-white-50" style={{ fontSize: '.7rem' }}></i>;
    return sortDir === 'asc'
      ? <i className="bi bi-chevron-up ms-1" style={{ fontSize: '.7rem' }}></i>
      : <i className="bi bi-chevron-down ms-1" style={{ fontSize: '.7rem' }}></i>;
  };

  // Totals
  const totalFine  = filtered.reduce((s, f) => s + f.fineAmount, 0);
  const unpaidFine = filtered.filter(f=>f.status==='Unpaid').reduce((s,f)=>s+f.fineAmount,0);
  const paidFine   = filtered.filter(f=>f.status==='Paid').reduce((s,f)=>s+f.fineAmount,0);

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* Header */}
        <div className="mb-4">
          <h2 className="section-title">
            <i className="bi bi-currency-rupee me-2" style={{ color: 'var(--accent)' }}></i>
            {isStudent ? 'My Fine Records' : 'Fine Management'}
          </h2>
          <p className="section-subtitle">
            {isStudent ? 'View your overdue fines and payment status' : 'All student fine records across the library'}
          </p>
        </div>

        {/* Summary cards */}
        <div className="row g-3 mb-4">
          <div className="col-sm-4">
            <div className="stat-card">
              <div className="stat-icon gold"><i className="bi bi-currency-rupee"></i></div>
              <div><div className="stat-value">₹{totalFine}</div><div className="stat-label">Total Fines</div></div>
            </div>
          </div>
          <div className="col-sm-4">
            <div className="stat-card">
              <div className="stat-icon red"><i className="bi bi-exclamation-circle"></i></div>
              <div><div className="stat-value" style={{ color: 'var(--danger)' }}>₹{unpaidFine}</div><div className="stat-label">Unpaid Amount</div></div>
            </div>
          </div>
          <div className="col-sm-4">
            <div className="stat-card">
              <div className="stat-icon green"><i className="bi bi-check-circle"></i></div>
              <div><div className="stat-value" style={{ color: '#059669' }}>₹{paidFine}</div><div className="stat-label">Paid Amount</div></div>
            </div>
          </div>
        </div>

        {/* Search & Filter */}
        <div className="lib-card p-3 mb-4">
          <div className="row g-3 align-items-end">
            <div className="col-md-5">
              <label className="lib-label">Search</label>
              <div className="input-group">
                <span className="input-group-text" style={{ border: '1.5px solid var(--border)', borderRight: 'none', background: '#f9f9fb' }}>
                  <i className="bi bi-search text-muted"></i>
                </span>
                <input type="text" className="form-control lib-form-control"
                  placeholder={isStudent ? "Search by book…" : "Search by student or book…"}
                  value={search} onChange={e => setSearch(e.target.value)}
                  style={{ borderLeft: 'none' }} />
                {search && <button className="btn btn-outline-secondary" onClick={() => setSearch('')} style={{ border: '1.5px solid var(--border)', borderLeft: 'none' }}><i className="bi bi-x"></i></button>}
              </div>
            </div>
            <div className="col-md-3">
              <label className="lib-label">Status</label>
              <select className="form-select lib-form-control" value={status} onChange={e => setStatus(e.target.value)}>
                <option>All</option>
                <option>Paid</option>
                <option>Unpaid</option>
              </select>
            </div>
            <div className="col-md-4 d-flex gap-2 align-items-center">
              <span className="badge-role badge-student" style={{ fontSize: '.8rem', padding: '.4em .9em' }}>
                {filtered.length} record{filtered.length !== 1 ? 's' : ''}
              </span>
              <button className="btn btn-lib-secondary btn-sm" onClick={() => { setSearch(''); setStatus('All'); }}>
                <i className="bi bi-arrow-counterclockwise me-1"></i>Reset
              </button>
            </div>
          </div>
        </div>

        {/* Table */}
        <div className="lib-card overflow-hidden">
          <div className="lib-card-header">
            <h5><i className="bi bi-table me-2"></i>Fine Records</h5>
          </div>
          <div className="table-responsive">
            <table className="lib-table">
              <thead>
                <tr>
                  <th style={{ width: 40 }}>#</th>
                  {!isStudent && <th style={{ cursor:'pointer' }} onClick={() => toggleSort('studentName')}>Student <SortIcon col="studentName" /></th>}
                  <th style={{ cursor:'pointer' }} onClick={() => toggleSort('bookTitle')}>Book Title <SortIcon col="bookTitle" /></th>
                  <th>Issued</th>
                  <th>Due Date</th>
                  <th>Returned</th>
                  <th style={{ textAlign:'center', cursor:'pointer' }} onClick={() => toggleSort('overdueDays')}>Overdue Days <SortIcon col="overdueDays" /></th>
                  <th style={{ textAlign:'center', cursor:'pointer' }} onClick={() => toggleSort('fineAmount')}>Fine (₹) <SortIcon col="fineAmount" /></th>
                  <th style={{ textAlign:'center' }}>Status</th>
                  {!isStudent && <th style={{ textAlign:'center' }}>Action</th>}
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr><td colSpan={10} className="text-center py-4"><span className="spinner-border text-primary"></span></td></tr>
                ) : filtered.length === 0 ? (
                  <tr>
                    <td colSpan={isStudent ? 8 : 10} className="text-center py-5 text-muted">
                      <i className="bi bi-check-circle d-block mb-2" style={{ fontSize: '2rem', color: '#06d6a0', opacity: .5 }}></i>
                      {isStudent ? 'No fine records found for your account.' : 'No records match the filter.'}
                    </td>
                  </tr>
                ) : filtered.map((f, i) => (
                  <tr key={f._id}>
                    <td style={{ color: 'var(--text-muted)', fontSize: '.82rem' }}>{i+1}</td>
                    {!isStudent && <td style={{ fontWeight: 500 }}>{f.student?.name}</td>}
                    <td style={{ maxWidth: '180px', fontSize: '.88rem' }}>{f.book?.title}</td>
                    <td style={{ fontSize: '.82rem' }}>{new Date(f.issueRecord?.issueDate || f.createdAt).toLocaleDateString()}</td>
                    <td style={{ fontSize: '.82rem', color: 'var(--danger)' }}>{new Date(f.dueDate).toLocaleDateString()}</td>
                    <td style={{ fontSize: '.82rem' }}>{f.returnDate ? new Date(f.returnDate).toLocaleDateString() : <span style={{ color: 'var(--text-muted)' }}>Not returned</span>}</td>
                    <td style={{ textAlign:'center' }}>
                      <span style={{ fontWeight: 700, color: f.overdueDays > 7 ? 'var(--danger)' : 'var(--gold)' }}>
                        {f.overdueDays}
                      </span>
                    </td>
                    <td style={{ textAlign:'center', fontWeight: 700, color: f.status==='Unpaid' ? 'var(--danger)' : '#059669' }}>
                      ₹{f.fineAmount}
                    </td>
                    <td style={{ textAlign:'center' }}>
                      <span className={`badge-role badge-${f.status.toLowerCase()}`}>{f.status}</span>
                    </td>
                    {!isStudent && (
                      <td style={{ textAlign:'center' }}>
                        {f.status === 'Unpaid' ? (
                          <button className="btn btn-sm btn-lib-primary" style={{ padding: '.2rem .65rem', fontSize: '.75rem' }}>
                            <i className="bi bi-check2 me-1"></i>Mark Paid
                          </button>
                        ) : (
                          <span style={{ color: 'var(--text-muted)', fontSize: '.78rem' }}>—</span>
                        )}
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
              {/* Footer totals row */}
              {filtered.length > 0 && (
                <tfoot>
                  <tr style={{ background: 'var(--primary)', color: '#fff' }}>
                    <td colSpan={isStudent ? 6 : 7} style={{ padding: '.75rem 1rem', fontWeight: 600, fontSize: '.85rem', color: 'rgba(255,255,255,.7)' }}>
                      Total ({filtered.length} records)
                    </td>
                    <td style={{ textAlign:'center', fontWeight: 700, color: 'var(--gold-light)' }}>
                      ₹{totalFine}
                    </td>
                    <td colSpan={isStudent ? 1 : 2} style={{ textAlign:'center', fontSize: '.82rem', color: 'rgba(255,255,255,.6)' }}>
                      Paid: <strong style={{ color: '#6dffce' }}>₹{paidFine}</strong>&nbsp;|&nbsp;
                      Unpaid: <strong style={{ color: '#ff9ab0' }}>₹{unpaidFine}</strong>
                    </td>
                  </tr>
                </tfoot>
              )}
            </table>
          </div>
        </div>

        {/* Fine policy note */}
        <div className="alert lib-alert mt-3" style={{ background: 'rgba(240,165,0,.08)', border: '1px solid rgba(240,165,0,.25)', color: '#92400e' }}>
          <i className="bi bi-info-circle-fill me-2"></i>
          <strong>Fine Policy:</strong> ₹5 per day after the due date. Fines must be cleared before new books can be borrowed.
        </div>
      </div>
    </div>
  );
};

export default FinesPage;
